    isPro = true;
    const refineButtonsInit = document.querySelectorAll(".refine-btn");
    refineButtonsInit.forEach((btn) => {
      btn.dataset.locked = "";
      const desc = btn.getAttribute("data-desc");
      if (desc) btn.title = desc;
    });
    const upgradeRow = document.getElementById("refine-upgrade");
    if (upgradeRow) upgradeRow.classList.add("hidden");
    const openOptions = document.getElementById("open-options");
    if (openOptions) {
      openOptions.addEventListener("click", (e2) => {
        e2.preventDefault();
        chrome.runtime.openOptionsPage();
      });
    }
    setupUploadInput(document.getElementById("file-input"));
    setupReplaceButton(document.getElementById("replace-btn"));
    const getJobBtn = document.getElementById("get-job-btn");
    if (getJobBtn) getJobBtn.addEventListener("click", getJobFromPage);
    const tailorBtn = document.getElementById("tailor-btn");
    if (tailorBtn) tailorBtn.addEventListener("click", tailorMyResume);
    const downloadBtn = document.getElementById("download-btn");
    if (downloadBtn) downloadBtn.addEventListener("click", handleDownloadPdf);
    const downloadDocxBtn = document.getElementById("download-docx-btn");
    if (downloadDocxBtn) downloadDocxBtn.addEventListener("click", handleDownloadDocx);
    const templateCards = document.querySelectorAll(".template-card");
    templateCards.forEach((card) => {
      card.addEventListener("click", () => {
        templateCards.forEach((c4) => c4.classList.remove("template-selected"));
        card.classList.add("template-selected");
        const radio = card.querySelector('input[type="radio"]');
        if (radio) radio.checked = true;
        updateDocxButtonState();
        if (radio) saveSessionState({ template: radio.value });
      });
    });
    const modeRadios = document.querySelectorAll('input[name="tailor-mode"]');
